sys_variable_value.value:
(function execute(inputs, outputs) {

    var body = JSON.parse(inputs.responseBody);

    if (!body.Contacts || body.Contacts.length === 0) {
        return;
    }

    var xeroUtils = new XeroIntegrationUtils();

    var result = xeroUtils.syncCompanyFromContact(
        body.Contacts[0]
    );

    outputs.company_sys_id = result.company_sys_id;
    outputs.is_new_company = result.is_new_company;

})(inputs, outputs);

